def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    P = list(map(int, data[1:N+1]))

    rank = [0] * N
    assigned = [False] * N
    r = 1

    while sum(assigned) < N:
        max_score = -1
        count = 0
        for i in range(N):
            if not assigned[i] and P[i] > max_score:
                max_score = P[i]
                count = 1
            elif not assigned[i] and P[i] == max_score:
                count += 1

        for i in range(N):
            if not assigned[i] and P[i] == max_score:
                rank[i] = r
                assigned[i] = True

        r += count

    for i in range(N):
        print(rank[i])

if __name__ == "__main__":
    main()
